// Parse the Google Chat interaction event and apply the sidecar's decision.
// The sidecar (Verify node) both (a) cryptographically verified the bearer
// token proves the caller is Google Chat, and (b) evaluated owner authorisation
// from the EVENT identity (never the token), returning authorized/authzState.
const verify = $input.first().json || {};
const wh = $('Webhook - Google Chat').first().json || {};
const body = wh.body || {};
const out = (o) => [{ json: o }];

// 1) Google request verification (fail => 401, no state change)
if (verify.verified !== true) {
  return out({ route: 'respond', httpCode: 401,
    responseBody: JSON.stringify({ text: 'Unauthorized.' }) });
}

const type = String(body.type || '');
const user = body.user || (body.message && body.message.sender) || {};
const user_email = String(user.email || '').toLowerCase();
const user_type = String(user.type || '');
const user_name = String(user.name || '');
const space = String((body.space && body.space.name)
  || (body.message && body.message.space && body.message.space.name) || '');

// 2) owner authorisation decision resolved server-side (binding / bootstrap)
const authorized = verify.authorized === true;
const authzState = String(verify.authzState || '');   // bound | bootstrap_captured | denied
const BOOTSTRAP_MSG = 'Owner identity captured. Awaiting confirmation in the implementation session.';

const priv = (obj) => { if (user_name) obj.privateMessageViewer = { name: user_name }; return obj; };

if (type === 'ADDED_TO_SPACE') {
  let msg;
  if (authorized) msg = 'Ready. In a prospect notification thread, mention @Instantly followed by your reply to draft a response.';
  else if (authzState === 'bootstrap_captured') msg = BOOTSTRAP_MSG;
  else msg = 'This console is restricted to the account owner.';
  return out({ route: 'respond', httpCode: 200, responseBody: JSON.stringify(priv({ text: msg })) });
}
if (type === 'REMOVED_FROM_SPACE') {
  return out({ route: 'respond', httpCode: 200, responseBody: JSON.stringify({}) });
}
if (!authorized) {
  const msg = (authzState === 'bootstrap_captured') ? BOOTSTRAP_MSG
    : 'This console is restricted to the account owner.';
  return out({ route: 'respond', httpCode: 200, responseBody: JSON.stringify(priv({ text: msg })) });
}

if (type === 'MESSAGE') {
  const msg = body.message || {};
  const threadName = String((msg.thread && msg.thread.name) || '');
  const threadKey = String((msg.thread && msg.thread.threadKey) || '');
  let text = String(msg.argumentText != null ? msg.argumentText : (msg.text || ''));
  // Preserve the EXACT multiline body: normalise line endings only, remove only
  // the app mention (argumentText already excludes it), trim OUTER boundary only.
  // NEVER collapse internal whitespace / newlines / blank lines.
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  if (msg.argumentText == null) { text = text.replace(/^[ \t]*@[^\s]+[ \t]*/, ''); }
  text = text.replace(/^\s+/, '').replace(/\s+$/, '');
  return out({ route: 'message', httpCode: 200, user_email, user_name, space,
    threadName, threadKey, replyBody: text,
    lookupUrl: threadName ? ('http://hmz-reply-console:5691/v1/context/by-thread?threadKey=' + encodeURIComponent(threadName))
                          : ('http://hmz-reply-console:5691/v1/context/by-thread?threadKey=' + encodeURIComponent(threadKey)) });
}

if (type === 'CARD_CLICKED') {
  const method = String((body.action && body.action.actionMethodName) || '');
  const params = {};
  const arr = (body.action && body.action.parameters) || [];
  for (const p of arr) params[p.key] = p.value;
  const inputs = (body.common && body.common.formInputs) || {};
  let editedBody = '';
  if (inputs.reply_body) {
    const v = inputs.reply_body;
    editedBody = String((v.stringInputs && v.stringInputs.value && v.stringInputs.value[0]) || '');
  }
  const cid = String(params.cid || '');
  return out({ route: 'card', httpCode: 200, user_email, user_name, space, method,
    contextId: cid, cardToken: String(params.tok || ''), editedBody,
    lookupUrl: 'http://hmz-reply-console:5691/v1/context/' + cid });
}

return out({ route: 'respond', httpCode: 200, responseBody: JSON.stringify({}) });

// Message path: validate the resolved context and prepare a draft request.
const p = $('Parse & Authorize').first().json;
const res = $input.first().json || {};
const ctx = res.ok && res.context ? res.context : null;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
const deny = (m) => [{ json: { decision:'deny', httpCode:200, responseBody: JSON.stringify(priv({ text: m })) } }];

// "refresh" command: surface the latest saved draft (no new revision, no send).
if (/^refresh(\s+latest)?(\s+review)?$/i.test(String(p.replyBody||'').trim())) {
  return [{ json: { decision:'refresh', contextId: ctx ? ctx.notificationId : '',
    refreshUrl: ctx ? ('http://hmz-reply-console:5691/v1/context/' + ctx.notificationId + '/refresh-card') : '' } }];
}
if (!p.replyBody) return deny('Your reply was empty. Reply in the thread and mention me with the text to send.');
if (p.replyBody.length > 8000) return deny('Reply too long.');
if (!ctx) return deny('No pending prospect reply is linked to this thread (it may have expired or already been answered).');
if (['SENT','SENDING','CANCELLED','EXPIRED','SEND_UNCERTAIN'].includes(ctx.state))
  return deny('This prospect reply is no longer open for a new draft (status: ' + ctx.state + ').');
// RETRYABLE (a prior send failed without delivery) IS re-draftable.

return [{ json: { decision:'draft', contextId: ctx.notificationId,
  draftUrl: 'http://hmz-reply-console:5691/v1/context/' + ctx.notificationId + '/draft',
  body: p.replyBody, author: p.user_email, user_name: p.user_name } }];

// Build the latest Review card from the refresh-card response (no send).
const rec = $input.first().json || {};
const p = $('Parse & Authorize').first().json;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
if (!rec.ok || !rec.revision) return [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ text: 'No draft to refresh yet. Reply with your message text to create one.' })) } }];
const CID = $('Handle Message').item.json.contextId;
const params = [{ key:'cid', value: CID }, { key:'tok', value: rec.reviewToken }];
const nl = (nm, addr) => (nm ? nm + ' ' : '') + '<' + (addr || '') + '>';
const esc = (t) => (t||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/\n/g,'<br>');
const card = { cardsV2:[{ cardId:'review-'+CID, card:{
  header:{ title:'Latest saved draft — revision '+rec.revision, subtitle:'To: '+(rec.prospectEmail||'') },
  sections:[
    { widgets:[
      { decoratedText:{ topLabel:'From (sender)', text: nl(rec.senderName, rec.eaccount) } },
      { decoratedText:{ topLabel:'To (prospect)', text: nl(rec.prospectName, rec.prospectEmail) } },
      { decoratedText:{ topLabel:'Subject', text: rec.subject || '(no subject)' } } ] },
    { header:'Exact reply body (revision '+rec.revision+')', widgets:[ { textParagraph:{ text: esc(rec.body) } } ] },
    { widgets:[ { buttonList:{ buttons:[
      { text:'Send', onClick:{ action:{ function:'send', parameters: params } } },
      { text:'Edit', onClick:{ action:{ function:'edit', interaction:'OPEN_DIALOG', parameters: params } } },
      { text:'Cancel', onClick:{ action:{ function:'cancel', parameters: params } } } ] } } ] },
    { widgets:[ { buttonList:{ buttons:[ { text:'Open in Instantly', onClick:{ openLink:{ url: rec.uniboxUrl||'https://app.instantly.ai' } } } ] } } ] },
  ] } }] };
return [{ json: { httpCode:200, responseBody: JSON.stringify(priv(card)) } }];

// Build the private review card with the EXACT outgoing body + Send/Edit/Cancel.
const d = $input.first().json || {};       // Create Draft response
const hm = $('Handle Message').item.json;
const p = $('Parse & Authorize').first().json;
const CID = hm.contextId;
// fetch context routing for from/to/subject via the draft response is not enough;
// we already have context fields from Resolve Context (thread) node output:
const rc = $('Resolve Context (thread)').item.json;
const ctx = (rc && rc.context) || {};
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
if (!d || d.ok !== true || !d.reviewToken) {
  return [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ text: 'Could not create the draft ('
    + ((d && d.reason) || 'error') + ').' })) } }];
}
const TOK = d.reviewToken;
const body = (ctx.activeDraft && ctx.activeDraft.body) || hm.body || '';
const params = [{ key:'cid', value: CID }, { key:'tok', value: TOK }];
const card = { cardsV2: [{ cardId: 'review-' + CID, card: {
  header: { title: '✍️ Review reply — revision ' + (d.revision||1),
            subtitle: 'To: ' + (ctx.prospectEmail||'') },
  sections: [
    { widgets: [
      { decoratedText: { topLabel: 'From (sender)', text: (ctx.senderName ? ctx.senderName + ' ' : '') + '<' + (ctx.eaccount || '') + '>' } },
      { decoratedText: { topLabel: 'To (prospect)', text: (ctx.prospectName ? ctx.prospectName + ' ' : '') + '<' + (ctx.prospectEmail || '') + '>' } },
      { decoratedText: { topLabel: 'Subject', text: ctx.subject || '(no subject)' } },
    ]},
    { header: 'Exact reply body', widgets: [ { textParagraph: { text: (body||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/\n/g,'<br>') } } ] },
    { widgets: [ { buttonList: { buttons: [
      { text: 'Send', onClick: { action: { function: 'send', parameters: params } } },
      { text: 'Edit', onClick: { action: { function: 'edit', interaction: 'OPEN_DIALOG', parameters: params } } },
      { text: 'Cancel', onClick: { action: { function: 'cancel', parameters: params } } },
    ] } } ] },
    { widgets: [ { buttonList: { buttons: [
      { text: 'Open in Instantly', onClick: { openLink: { url: ctx.uniboxUrl || 'https://app.instantly.ai' } } } ] } } ] },
  ] } }] };
return [{ json: { httpCode:200, responseBody: JSON.stringify(priv(card)) } }];

// Card action router. Card params carry only opaque cid + one-use token.
const p = $('Parse & Authorize').first().json;
const res = $input.first().json || {};
const ctx = res.ok && res.context ? res.context : null;
const method = p.method || '';
const base = { user_name: p.user_name, user_email: p.user_email, contextId: p.contextId,
  cardToken: p.cardToken, editedBody: p.editedBody, method, ctx };
if (!ctx) { base.action = 'blocked'; base.reason = 'context_not_found'; return [{ json: base }]; }
if (['send','edit','cancel','dialog_submit','check_status'].includes(method)) { base.action = method; }
else { base.action = 'blocked'; base.reason = 'unknown_action'; }
return [{ json: base }];

const s = $input.first().json || {};
const p = $('Parse & Authorize').first().json;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
const done = (text) => [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ text })) } }];
if (s.state === 'SENT_RECONCILED_READBACK' || s.state === 'SENT_RECONCILED_WEBHOOK' || s.state === 'SENT_API_CONFIRMED') return done('✅ Sent — confirmed in Instantly.');
if (s.state === 'MANUAL_RECONCILIATION_REQUIRED') {
  const c = ($('Card Router').item.json.ctx) || {};
  const nl = (nm, addr) => (nm ? nm + ' ' : '') + '<' + (addr || '') + '>';
  return done(['⚠️ Delivery could not be confirmed automatically.','',
    '*Prospect:* ' + nl(c.prospectName, c.prospectEmail),
    '*Sender:* ' + nl(c.senderName, c.eaccount),'',
    'No second email has been attempted. Open the Instantly thread to verify before taking any further action.'].join('\n'));
}
if (s.state === 'RETRYABLE' || s.state === 'FAILED_DEFINITIVE') return done('⛔ Not sent. You can reply again to draft a fresh version.');
return done('🟡 Still checking delivery with Instantly. Please check again shortly. Do not click Send again.');

// Render the send result from the sidecar's atomic performSend response.
const s = $input.first().json || {};
const p = $('Parse & Authorize').first().json;
const cid = $('Card Router').item.json.contextId;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
const done = (text) => [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ text })) } }];
// A card with a Check-status button (no second Send).
const ctx = ($('Card Router').item.json.ctx) || {};
const nameLine = (nm, addr) => (nm ? nm + ' ' : '') + '<' + (addr || '') + '>';
const statusCard = (title, exceptional) => {
  const params = [{ key:'cid', value: cid }];
  const body = exceptional
    ? ('*Prospect:* ' + nameLine(ctx.prospectName, ctx.prospectEmail) + '\n*Sender:* ' + nameLine(ctx.senderName, ctx.eaccount)
       + '\n\nNo second email has been attempted. Open the Instantly thread to verify before taking any further action.')
    : 'The email may already be delivered. Do not click Send again.';
  return [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ cardsV2:[{ cardId:'recon-'+cid, card:{
    header:{ title }, sections:[ { widgets:[
      { textParagraph:{ text: body } },
      { buttonList:{ buttons:[
        { text:'Check status', onClick:{ action:{ function:'check_status', parameters: params } } },
        { text:'Open in Instantly', onClick:{ openLink:{ url: s.uniboxUrl || (ctx.uniboxUrl) || 'https://app.instantly.ai' } } } ] } } ] } ] } }] })) } }];
};
const nowLon = new Date().toLocaleString('en-GB', { timeZone: 'Europe/London' });
const nowUtc = new Date().toISOString();
const receipt = (headline, confirm) => done([headline, '',
  '*Prospect:* ' + nameLine(ctx.prospectName, ctx.prospectEmail),
  '*Sender:* ' + nameLine(ctx.senderName, ctx.eaccount),
  '*Subject:* ' + (ctx.subject || '(no subject)'),
  '*Confirmation:* ' + confirm,
  '*Time:* ' + nowLon + ' (London) / ' + nowUtc + ' (UTC)'].join('\n'));
if (s.outcome === 'SENT_API_CONFIRMED') return receipt('✅ Sent', 'Sent — API confirmed');
if (s.state === 'SENT_RECONCILED_READBACK' || s.state === 'SENT_RECONCILED_WEBHOOK' || s.reconciled) return receipt('✅ Sent', 'Sent — confirmed by Instantly reconciliation');
if (s.outcome === 'FAILED_DEFINITIVE') return done('⛔ Blocked — Instantly rejected the send (http ' + (s.httpStatus||'?') + '). No email was sent; you can reply again to draft a fresh version.');
if (s.state === 'MANUAL_RECONCILIATION_REQUIRED') return statusCard('⚠️ Delivery could not be confirmed automatically', true);
if (s.state === 'RECONCILING' || s.outcome === 'RECONCILING') return statusCard('🟡 Confirming delivery with Instantly', false);
// Stale/outdated card recovery: surface the LATEST review card with a fresh
// one-use token so the owner is never trapped. Never sent the newer revision.
if (s.staleRecovery && s.staleRecovery.ok !== false && s.staleRecovery.revision) {
  const rec = s.staleRecovery;
  const CID = $('Card Router').item.json.contextId;
  const TOK = rec.reviewToken;
  const params = [{ key:'cid', value: CID }, { key:'tok', value: TOK }];
  const nl = (nm, addr) => (nm ? nm + ' ' : '') + '<' + (addr || '') + '>';
  const esc = (t) => (t||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/\n/g,'<br>');
  const card = { cardsV2:[{ cardId:'review-'+CID, card:{
    header:{ title:'🔄 This card was outdated — showing the latest saved draft (revision '+rec.revision+')', subtitle:'To: '+(rec.prospectEmail||'') },
    sections:[
      { widgets:[
        { decoratedText:{ topLabel:'From (sender)', text: nl(rec.senderName, rec.eaccount) } },
        { decoratedText:{ topLabel:'To (prospect)', text: nl(rec.prospectName, rec.prospectEmail) } },
        { decoratedText:{ topLabel:'Subject', text: rec.subject || '(no subject)' } } ] },
      { header:'Exact reply body (revision '+rec.revision+')', widgets:[ { textParagraph:{ text: esc(rec.body) } } ] },
      { widgets:[ { buttonList:{ buttons:[
        { text:'Send', onClick:{ action:{ function:'send', parameters: params } } },
        { text:'Edit', onClick:{ action:{ function:'edit', interaction:'OPEN_DIALOG', parameters: params } } },
        { text:'Cancel', onClick:{ action:{ function:'cancel', parameters: params } } } ] } } ] },
      { widgets:[ { buttonList:{ buttons:[ { text:'Open in Instantly', onClick:{ openLink:{ url: rec.uniboxUrl||'https://app.instantly.ai' } } } ] } } ] },
    ] } }] };
  return [{ json: { httpCode:200, responseBody: JSON.stringify(priv(card)) } }];
}
const reason = s.reason || 'blocked';
const map = { SEND_DISABLED_NOT_GO_LIVE:'Sending is not yet enabled (go-live pending explicit owner approval). Review, Edit and Cancel work; no email was sent.',
  SEND_DISABLED_WRONG_CONTEXT:'Sending is armed for a different context. No email was sent.',
  SEND_DISABLED_WRONG_REVISION:'Sending is armed for a different revision; re-review the latest draft. No email was sent.',
  ALREADY_SENT:'This reply was already sent.', SEND_IN_PROGRESS:'A send is already in progress.', RECONCILING_IN_PROGRESS:'Delivery is being confirmed; do not resend.',
  LOCK_ALREADY_HELD:'A send is already in progress (duplicate click ignored).', TOKEN_USED:'This approval was already used.',
  TOKEN_EXPIRED:'This approval expired — reply again to draft a fresh version.', TOKEN_MISMATCH:'Approval token invalid (superseded by an edit).',
  BODY_TAMPERED:'The reviewed body no longer matches — send blocked.',
  NO_API_KEY_CONFIGURED:'Send key not configured. No email was sent.', context_not_found:'Context not found or expired.' };
return done('⛔ ' + (map[reason] || ('Send blocked (' + reason + ').')) + ' No second email was sent.');

const a = $input.first().json || {};
const p = $('Parse & Authorize').first().json;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
const reason = a.reason || 'blocked';
const map = { SEND_DISABLED_NOT_GO_LIVE:'Sending is not yet enabled (go-live pending explicit owner approval). Review, Edit and Cancel work; no email was sent.',
  SEND_DISABLED_WRONG_CONTEXT:'Sending is armed for a different context. No email was sent.',
  SEND_DISABLED_WRONG_REVISION:'Sending is armed for a different revision; re-review the latest draft. No email was sent.',
  ALREADY_SENT:'This reply was already sent.', SEND_IN_PROGRESS:'A send is already in progress.',
  LOCK_ALREADY_HELD:'A send is already in progress (duplicate click ignored).', TOKEN_USED:'This approval was already used.',
  TOKEN_EXPIRED:'This approval expired — reply again to draft a fresh version.', TOKEN_MISMATCH:'Approval token invalid.',
  BODY_TAMPERED:'The reviewed body no longer matches — send blocked.', SEND_UNCERTAIN:'Previous send is uncertain; reconcile in Instantly first.',
  context_not_found:'Context not found or expired.' };
return [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ text: '⛔ ' + (map[reason] || ('Send blocked (' + reason + ').')) + ' No second email was sent.' })) } }];

const j = $input.first().json;
const ctx = j.ctx || {};
const body = (ctx.activeDraft && ctx.activeDraft.body) || '';
const params = [{ key:'cid', value: j.contextId }, { key:'tok', value: j.cardToken }];
const dialog = { actionResponse: { type: 'DIALOG', dialogAction: { dialog: { body: { sections: [ { widgets: [
  { textInput: { name: 'reply_body', label: 'Reply body', type: 'MULTIPLE_LINE', value: body } },
  { buttonList: { buttons: [
    { text: 'Save & Review', onClick: { action: { function: 'dialog_submit', parameters: params } } } ] } },
] } ] } } } } };
return [{ json: { httpCode:200, responseBody: JSON.stringify(dialog) } }];

const p = $('Parse & Authorize').first().json;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
return [{ json: { httpCode:200, responseBody: JSON.stringify(priv({ text: '🚫 Cancelled. No email was sent.' })) } }];

// Dialog submit: create a new draft revision from the edited body.
const j = $input.first().json;
const body = String(j.editedBody || '').replace(/\r\n/g,'\n').replace(/\r/g,'\n').replace(/^\s+/,'').replace(/\s+$/,'');
if (!body) return [{ json: { httpCode:200, responseBody: JSON.stringify({ actionResponse: { type:'DIALOG',
  dialogAction: { actionStatus: { statusCode:'INVALID_ARGUMENT', userFacingMessage:'Reply cannot be empty.' } } } }) } }];
return [{ json: { contextId: j.contextId, body, author: j.user_email, user_name: j.user_name,
  ctx: j.ctx, draftUrl: 'http://hmz-reply-console:5691/v1/context/' + j.contextId + '/draft' } }];

// Rebuild the review card after an edit; close dialog by returning a message.
const d = $input.first().json || {};
const prep = $('Prep Edit Draft').item.json;
const p = $('Parse & Authorize').first().json;
const priv = (o) => { if (p.user_name) o.privateMessageViewer = { name: p.user_name }; return o; };
if (!d || d.ok !== true || !d.reviewToken) {
  return [{ json: { httpCode:200, responseBody: JSON.stringify({ actionResponse:{ type:'DIALOG',
    dialogAction:{ actionStatus:{ statusCode:'INTERNAL', userFacingMessage:'Could not save edit.' } } } }) } }];
}
const CID = prep.contextId, TOK = d.reviewToken, ctx = prep.ctx || {};
const body = prep.body;
const params = [{ key:'cid', value: CID }, { key:'tok', value: TOK }];
const card = { cardsV2: [{ cardId: 'review-' + CID, card: {
  header: { title: '✍️ Review reply — revision ' + (d.revision||2), subtitle: 'To: ' + (ctx.prospectEmail||'') },
  sections: [
    { widgets: [
      { decoratedText: { topLabel:'From (sender)', text: (ctx.senderName ? ctx.senderName + ' ' : '') + '<' + (ctx.eaccount||'') + '>' } },
      { decoratedText: { topLabel:'To (prospect)', text: (ctx.prospectName ? ctx.prospectName + ' ' : '') + '<' + (ctx.prospectEmail||'') + '>' } },
      { decoratedText: { topLabel:'Subject', text: ctx.subject||'(no subject)' } } ] },
    { header:'Exact reply body', widgets:[ { textParagraph: { text: (body||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/\n/g,'<br>') } } ] },
    { widgets:[ { buttonList: { buttons: [
      { text:'Send', onClick:{ action:{ function:'send', parameters: params } } },
      { text:'Edit', onClick:{ action:{ function:'edit', interaction:'OPEN_DIALOG', parameters: params } } },
      { text:'Cancel', onClick:{ action:{ function:'cancel', parameters: params } } } ] } } ] },
    { widgets:[ { buttonList:{ buttons:[ { text:'Open in Instantly', onClick:{ openLink:{ url: ctx.uniboxUrl||'https://app.instantly.ai' } } } ] } } ] },
  ] } }] };
// SUBMIT_DIALOG response MUST carry an actionResponse envelope. UPDATE_MESSAGE
// closes the dialog and replaces the card that opened it with the new revision.
const resp = priv({ actionResponse: { type: 'UPDATE_MESSAGE' }, cardsV2: card.cardsV2 });
return [{ json: { httpCode:200, responseBody: JSON.stringify(resp) } }];
